#!/bin/bash
#Accepts command line arg:
# 't' : Training mode (Generates a network as a file)
# 'r' : Running mode (Runs on network generated by training mode)


set -e #Immediately exit upon failure


DATA_DIR="./data/MNIST"
mkdir -p "$DATA_DIR"
cd "$DATA_DIR"

download_if_needed() {
    FILE=$1
    URL=$2
    RAW="${FILE%.gz}"


    if [ ! -f "$FILE" ] && [ ! -f "$RAW" ]; then
        echo "Downloading $FILE"
        curl -L -o "$FILE" "$URL"
    else
        echo "$FILE already exists"
    fi
}


unzip_if_needed() {
    FILE=$1
    if [ -f "$FILE.gz" ] && [ ! -f "$FILE" ]; then
        echo "Unzipping $FILE"
        gunzip "$FILE.gz"
    fi

}

download_if_needed train-images-idx3-ubyte.gz https://storage.googleapis.com/cvdf-datasets/mnist/train-images-idx3-ubyte.gz
download_if_needed train-labels-idx1-ubyte.gz https://storage.googleapis.com/cvdf-datasets/mnist/train-labels-idx1-ubyte.gz
download_if_needed t10k-images-idx3-ubyte.gz https://storage.googleapis.com/cvdf-datasets/mnist/t10k-images-idx3-ubyte.gz
download_if_needed t10k-labels-idx1-ubyte.gz https://storage.googleapis.com/cvdf-datasets/mnist/t10k-labels-idx1-ubyte.gz

unzip_if_needed train-images-idx3-ubyte
unzip_if_needed train-labels-idx1-ubyte
unzip_if_needed t10k-images-idx3-ubyte
unzip_if_needed t10k-labels-idx1-ubyte


echo "MNIST ready"

cd "../.."

mkdir -p ./bin
clang++ ./testing/MNIST/bench.c++ -O3 -o ./bin/a.out
./bin/a.out $1






